182			.mem_req_valid_o    (mem_req_valid_o  ),
183			.mem_req_o          (mem_req_o        ),
184			.cache_ready_i      (cache_ready_i    ),
185			//Cache Interface (IN)
186			.mem_resp_valid_i   (mem_resp_valid_i ),
