196			.rd_pending_1_i     (mem_pending_1    ),
197			.rd_ticket_1_i      (mem_ticket_1     ),
198			.rd_addr_2_o        (mem_addr_2       ),
199			.rd_data_2_i        (mem_data_2       ),
200			.rd_pending_2_i     (mem_pending_2    ),
201			.rd_ticket_2_i      (mem_ticket_2     ),
202			//RF Writeback Interface
203			.wrtbck_en_o        (mem_wrtbck_en    ),
204			.wrtbck_reg_o       (mem_wrtbck_reg   ),
205			.wrtbck_data_o      (mem_wrtbck_data  ),
206			.wrtbck_ticket_o    (mem_wrtbck_ticket),
207			//RF Writeback Probing Interface
208			.wrtbck_prb_reg_o   (mem_prb_reg      ),
209			.wrtbck_prb_locked_i(mem_prb_locked   ),
210			.wrtbck_prb_ticket_i(mem_prb_ticket   ),
211			//Unlock Interface
212			.unlock_en_o        (unlock_en        ),
213			.unlock_reg_a_o     (unlock_reg_a     ),
214			.unlock_reg_b_o     (unlock_reg_b     ),
215			.unlock_ticket_o    (unlock_ticket    )
216		);
